local LoadSceneMode = UnityEngine.SceneManagement.LoadSceneMode
local LxBaseMgr = require("LApp.Manager.LxBaseMgr")
---@class LxLevelMgr:LxBaseMgr
local LxLevelMgr = classX("LxLevelMgr", LxBaseMgr)

LxRequire('LApp.Scene.Base.LMapBase')
LxRequire('LApp.Scene.Base.LBubbleBase')

local BUILTIN_LEVEL = {
    [LevelNames.Empty] = true,
    [LevelNames.Loader] = true,
    [LevelNames.Update] = true,
    [LevelNames.Login] = true,
    [LevelNames.Init] = true,
}

function LxLevelMgr:Initialize()
    LxBaseMgr.Initialize(self)

    ---@type LxResRequester
    self._resRequester = nil

    self._curLevelName = nil
end

function LxLevelMgr:Dispose()
    self:ClearResRequester()

    LxBaseMgr.Dispose(self)
end

function LxLevelMgr:ClearResRequester()
    if self._resRequester ~= nil then
        self._resRequester:Dispose()
        self._resRequester = nil
    end
end

function LxLevelMgr:IsInLevel(levelName)
    return self._curLevelName and levelName == self._curLevelName
end

function LxLevelMgr:SetCurrentLevelName(levelName)
    self._curLevelName = levelName
end

function LxLevelMgr:ExecuteLevelLoad(levelName, loadSceneMode)
    self:ClearResRequester()

    MgrCenter.ResourceMgr:UnloadAllScene()

    if BUILTIN_LEVEL[levelName] then
        if LOG_INFO_ENABLED then
            printInfo("LevelMgr", "--->>>load builtin level \"%s\", mode is %s", levelName, tostring(loadSceneMode))
        end
        LxResUtil.LoadBuiltinSceneAsync(levelName, loadSceneMode)
    else
        if LOG_INFO_ENABLED then
            printInfo("LevelMgr", "--->>>load bundle level \"%s\", mode is %s", levelName, tostring(loadSceneMode))
        end
        local assetPath = "Map/Scene/"..levelName..".unity"
        self._resRequester = LxResUtil.GetSceneRequester(assetPath, loadSceneMode, false, 100, nil)
        self._resRequester:StartRequester()
    end
end

function LxLevelMgr:LoadLevel(levelName, levelParams, loadParams)
    if LGameRunMode:IsLoading() then return end

    self:SetChangeSceneRemainParams()

    if LOG_INFO_ENABLED then
        printInfo("LevelMgr", "--->>>start load level which name is \"%s\"", levelName)
    end

    ---@type LxLoaderAdapter
    local loadAdapter = MgrCenter.AdapterMgr:GetAdapter(LevelNames.Loader)
    if loadAdapter:IsLoading() then
        if LOG_INFO_ENABLED then
            printInfo("LevelMgr", "--->>>exist loading from \"%s\" to \"%s\"", tostring(loadAdapter:GetOldLevelName()),loadAdapter:GetTargetLevelName())
        end
    end

    loadParams = loadParams or {}

    local targetAdapter = MgrCenter.AdapterMgr:GetAdapter(levelName)
    if levelParams then
        targetAdapter:SetParam(levelParams)
    end

    local oldLevelName = self._curLevelName
    loadAdapter:StartLoadLevel(levelName, oldLevelName,loadParams)
end


function LxLevelMgr:OnLevelLoaded(scene, loadMode)
    local name = scene.name
    if name == "xinit" then return end

    if LOG_INFO_ENABLED then
        printInfo("LevelMgr", "<color=#01c40c>--->>>OnLevelLoaded, name is \"%s\"</color>" , name)
    end

    local adapter = MgrCenter.AdapterMgr:GetAdapter(name)
    if not adapter then
        LogError("--->>>LevelLoaded not match adapter which name is " .. tostring(name))
        return
    end

    if name == LevelNames.Loader then
        adapter:OnEnterLevel(scene, loadMode)
        return
    end

    ---@type LxLoaderAdapter
    local loaderAdapter = MgrCenter.AdapterMgr:GetAdapter(LevelNames.Loader)
    loaderAdapter:OnTargetLevelLoaded(scene, loadMode)
end

function LxLevelMgr:OnLevelUnloaded(scene)
    local name = scene.name
    if name == LevelNames.Init then return end

    if LOG_INFO_ENABLED then
        printInfo("LevelMgr", "<color=#ff000c>--->>>OnLevelUnloaded ,  name is \"%s\"</color>" , scene.name)
    end

    local adapter = MgrCenter.AdapterMgr:GetAdapter(name)
    if not adapter then
        LogError("--->>>LevelUnloaded not match adapter which name is " .. tostring(name))
        return
    end
    adapter:OnLeaveLevel(scene)
end

function LxLevelMgr:OnLevelChanged(prevName, newName)
    self._curLevelName = newName
    local adapter = MgrCenter.AdapterMgr:GetAdapter(prevName)
    if adapter then
        adapter:OnWillLeaveLevel()
    end
end


function LxLevelMgr:OnAppScreenResize()
    local scene = self:GetCurrentScene()
    if scene then scene:OnCameraAdapt() end
end
-----------------------------------------------------------------

---@type LxBaseAdapter
function LxLevelMgr:GetCurrentScene()
    local adapter = MgrCenter.AdapterMgr:GetAdapter(self._curLevelName)
    return adapter
end


function LxLevelMgr:GetCurrentSceneCamera()
    local scene = self:GetCurrentScene()
    local camera = scene and scene:GetSceneMainCamera() or nil
    if not camera then
        camera = UnityEngine.Camera.main
    end
    return camera
end

function LxLevelMgr:IsCurrentScene(levelName)
    return self:IsInLevel(levelName)
end

function LxLevelMgr:CheckChangeRemainScene()
    local remainChangeSceneParams = self._changeSceneRemainParams
    if not remainChangeSceneParams then return end
    
    self._changeSceneRemainParams = nil

    self:LoadLevel(remainChangeSceneParams.levelName,remainChangeSceneParams.argList)
end

function LxLevelMgr:SetChangeSceneRemainParams(levelName,argList)
    if not sceneClassName then
        self._changeSceneRemainParams = nil
        return
    end
    self._changeSceneRemainParams = {levelName=levelName,argList=argList}
end

function LxLevelMgr:OnApplicationPause(isPause)
    local currentScene = self:GetCurrentScene()
    if currentScene then
        currentScene:OnApplicationPause(isPause)
    end
end


return LxLevelMgr